head.script:
//
// Initialize user preferences
!function() {
  var root = document.documentElement;
  var theme = localStorage.getItem("theme") || (window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light");
  var lang = localStorage.getItem("lang");
  var variant = localStorage.getItem("variant");

  if (!lang) {
    var userLang = (navigator.language || navigator.userLanguage).toLowerCase();
    lang = userLang.includes("zh") ? "zh" : "en";
    variant = userLang.match(/(tw|hk|mo|hant)/) ? "trad" : "simp";
    localStorage.setItem("lang", lang);
    localStorage.setItem("variant", variant);
  }

  root.setAttribute("data-theme", theme);
  root.setAttribute("data-lang", lang);
  root.setAttribute("data-variant", variant || "simp");
}();
//

head.b:skin:
/* Light theme */
:root {
  --bg-color: #fcfcfb;
  --text-color: #2b2b2b;
  --meta-color: #737373;
  --accent-color: #6a8c50; 
  --accent-bg: rgba(106, 140, 80, 0.1); 
  --btn-bg: rgba(0, 0, 0, 0.03); 
  --border-color: #eaeaea;
  --icon-color: #555;
  --container-width: 700px;
  --transition: 0.4s ease;
}

/* Dark theme */
[data-theme="dark"] {
  --bg-color: #161618;
  --text-color: #dcdcdc;
  --meta-color: #8a8a8a;
  --accent-color: #a0c184; 
  --accent-bg: rgba(160, 193, 132, 0.1);
  --btn-bg: rgba(255, 255, 255, 0.05);
  --border-color: #2a2a2c;
  --icon-color: #aaa;
}

/* Global reset */
* { 
  box-sizing: border-box; 
}

body {
  margin: 0;
  padding: 0;
  background: var(--bg-color);
  color: var(--text-color);
  font-family: 'Inter', "PingFang SC", "Microsoft YaHei", sans-serif;
  line-height: 1.8;
  font-size: 16px;
  transition: background var(--transition), color var(--transition);
  -webkit-font-smoothing: antialiased;
}

a {
  color: inherit;
  text-decoration: none;
  transition: color 0.3s ease;
}

a:hover { 
  color: var(--accent-color); 
}

/* Buttons */
.post-tag, 
.read-more, 
.blog-pager a, 
.comment-toggle-btn, 
.main-nav li a {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 8px 20px;
  background: var(--btn-bg);
  color: var(--text-color);
  border: 1px solid transparent;
  border-radius: 30px;
  min-height: 40px;
  transition: all 0.3s ease;
  font-weight: 500;
  font-size: 0.95rem;
  cursor: pointer;
  text-decoration: none;
  font-family: inherit;
  letter-spacing: 0.5px;
}

.main-nav li a { 
  font-size: 0.9rem; 
}

.post-tag { 
  margin: 4px 6px 4px 0; 
}

.read-more, 
.blog-pager a, 
.comment-toggle-btn {
  padding: 10px 24px;
  min-height: 48px;
}

.read-more { 
  margin-top: 15px; 
}

.comment-toggle-btn {
  width: 100%;
  max-width: 350px;
  display: flex;
  margin: 0 auto 20px auto;
}

.post-tag:hover, 
.read-more:hover, 
.blog-pager a:hover, 
.comment-toggle-btn:hover, 
.main-nav li a:hover {
  background: var(--accent-bg);
  color: var(--accent-color);
  transform: translateY(-2px);
}

.post-tag:active, 
.read-more:active, 
.blog-pager a:active, 
.comment-toggle-btn:active, 
.main-nav li a:active {
  transform: scale(0.96);
}

/* Layout */
.outer-wrapper {
  max-width: var(--container-width);
  margin: 0 auto;
  padding: 0 25px;
  position: relative;
}

.site-header, 
nav.main-nav, 
#main-content, 
.site-footer, 
.top-actions {
  transition: opacity 0.35s ease, transform 0.35s ease;
}

.content-fade-out {
  opacity: 0 !important;
  transform: translateY(8px) !important;
  pointer-events: none;
}

/* Toggles */
.top-actions {
  position: absolute;
  top: 30px;
  right: 25px;
  display: flex;
  gap: 12px;
  z-index: 10;
}

.action-btn {
  background: none;
  border: none;
  color: var(--icon-color);
  cursor: pointer;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 48px;
  height: 48px;
  transition: all 0.3s ease;
}

.action-btn:hover {
  background: var(--btn-bg);
  color: var(--accent-color);
  transform: translateY(-2px);
}

#theme-icon { 
  width: 22px; 
  height: 22px; 
  transition: transform 0.5s cubic-bezier(0.4, 0, 0.2, 1); 
}

[data-theme="dark"] #theme-icon { 
  transform: rotate(90deg); 
}

.sun-icon { 
  display: none; 
  stroke: currentColor; 
  stroke-width: 2; 
  stroke-linecap: round; 
  stroke-linejoin: round; 
  fill: none; 
}

.moon-icon { 
  display: block; 
  fill: currentColor; 
  stroke: none; 
}

[data-theme="dark"] .sun-icon { display: block; }
[data-theme="dark"] .moon-icon { display: none; }

.text-toggle-btn {
  font-family: 'EB Garamond', serif;
  font-size: 1rem;
  font-weight: 500;
}

/* Language logic */
[data-lang="zh"] .lang-en, 
[data-lang="en"] .lang-zh,
[data-variant="simp"] .variant-trad, 
[data-variant="trad"] .variant-simp { 
  display: none !important; 
}

#variant-toggle { 
  transition: width 0.3s ease, margin 0.3s ease, opacity 0.3s ease, transform 0.3s ease; 
}

[data-lang="en"] #variant-toggle {
  opacity: 0; 
  visibility: hidden; 
  transform: scale(0.5); 
  width: 0; 
  margin-left: -12px; 
  pointer-events: none;
}

/* Header */
.site-header { 
  padding: 80px 0 30px; 
  text-align: left; 
}

.header-title h1 {
  font-family: 'EB Garamond', serif;
  font-weight: 500;
  font-size: 2.4rem;
  margin: 0;
  letter-spacing: -0.5px;
  word-break: keep-all;
  overflow-wrap: break-word;
  text-wrap: balance;
}

.header-logo-link {
  display: inline-flex;
  align-items: center;
  justify-content: flex-start;
  gap: 18px;
  border: none !important;
  padding: 12px 0;
  min-height: 60px;
  transition: transform 0.3s ease;
}

.header-logo-link:hover { 
  transform: scale(1.02); 
}

.header-logo-link svg { 
  flex-shrink: 0 !important; 
  width: 55px; 
  height: 55px; 
}

.header-desc { 
  font-size: 0.95rem; 
  color: var(--meta-color); 
  margin-top: 15px; 
  font-style: italic; 
  text-align: center; 
}

/* Navigation */
nav.main-nav { 
  margin-bottom: 35px; 
  text-align: center; 
}

.main-nav ul { 
  margin: 0; 
  padding: 0; 
  list-style: none; 
  display: flex; 
  justify-content: center; 
  flex-wrap: wrap; 
  gap: 12px 16px; 
}

.main-nav li { 
  display: inline-block; 
  margin: 0; 
}

/* Posts */
.post-outer { 
  margin-bottom: 70px; 
  content-visibility: auto; 
  contain-intrinsic-size: 100px 500px;
}

h2.post-title {
  font-family: 'EB Garamond', serif; 
  font-size: 1.85rem; 
  margin: 0 0 10px;
  line-height: 1.5; 
  font-weight: 500; 
  word-break: keep-all; 
  overflow-wrap: break-word; 
  text-wrap: balance;
}

h2.post-title a { 
  border: none; 
  display: inline-block; 
  padding: 10px 0; 
  min-height: 48px; 
  transition: all 0.3s ease; 
}

h2.post-title a:hover { 
  color: var(--accent-color); 
  transform: translateX(2px); 
}

.post-meta { 
  font-size: 0.85rem; 
  color: var(--meta-color); 
  margin-bottom: 20px; 
  letter-spacing: 0.5px; 
  display: flex; 
  flex-wrap: wrap; 
  align-items: center; 
}

.post-body.full-content { 
  font-size: 1.15rem; 
  word-break: break-word;
}

.post-body a { 
  padding: 2px 4px; 
  display: inline-block; 
  border-bottom: 1px solid currentColor; 
  margin: -2px 0; 
  transition: all 0.3s ease;
}

.post-body a:hover {
  color: var(--accent-color);
  border-bottom-color: var(--accent-color);
}

.post-body a:has(img) {
  border-bottom: none !important;
  padding: 0 !important;
  margin: 0 !important;
  display: block;
}

.post-body img { 
  max-width: 100%; 
  height: auto; 
  border-radius: 8px; 
  margin: 30px auto; 
  display: block; 
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
  transition: transform 0.4s ease, box-shadow 0.4s ease;
}

[data-theme="dark"] .post-body img { 
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.4); 
}

.post-body img:hover {
  transform: scale(1.01);
  box-shadow: 0 6px 25px rgba(0, 0, 0, 0.12);
}

[data-theme="dark"] .post-body img:hover { 
  box-shadow: 0 6px 25px rgba(0, 0, 0, 0.5); 
}

.separator { 
  border: none !important; 
  background: transparent !important; 
}

.post-body.snippet-content { 
  font-size: 1.05rem; 
  color: var(--meta-color); 
  margin-bottom: 15px; 
}

.featured-img-wrapper img {
  width: 100%; 
  aspect-ratio: 16/9; 
  height: auto; 
  object-fit: cover;
  border-radius: 8px; 
  margin-bottom: 15px; 
  display: block; 
  box-shadow: none; 
  transition: transform 0.5s ease;
}

.featured-img-wrapper:hover img { 
  transform: scale(1.02); 
  box-shadow: none; 
}

/* Pagination */
.blog-pager { 
  padding: 10px 0; 
  text-align: center; 
  font-size: 0.95rem; 
  display: flex; 
  justify-content: center; 
  flex-wrap: wrap; 
  gap: 16px; 
}

/* Related posts & headers */
.related-posts, 
.comments-wrapper { 
  margin-top: 30px; 
  padding-top: 20px; 
  border-top: 1px solid var(--border-color); 
}

.related-posts h3, 
.comments-wrapper h3 { 
  font-family: 'EB Garamond', serif; 
  font-size: 1.5rem; 
  margin-bottom: 15px; 
  font-weight: 500; 
}

.related-posts ul { 
  list-style: none; 
  padding: 0; 
  margin: 0; 
  display: grid; 
  gap: 12px; 
}

.related-posts li a { 
  display: inline-block; 
  font-size: 1.05rem; 
  color: var(--text-color); 
  border-bottom: 1px dashed var(--meta-color); 
  transition: all 0.3s ease; 
  padding: 4px 0; 
}

.related-posts li a:hover { 
  color: var(--accent-color); 
  border-bottom-color: var(--accent-color); 
  transform: translateX(4px); 
}

/* Comments */
.comments { 
  position: relative; 
  padding-left: 0; 
}

.comments .comment::before, 
.comments .comment::after,
.comments .comment-thread ol::before, 
.comments .comment-thread ol::after,
#comment-holder > .comment-replybox-thread, 
.comment-thread .comment-replybox-thread { 
  display: none !important; 
  content: none !important; 
  height: 0 !important; 
  border: none !important;
}

#custom-comment-form-container { 
  display: grid; 
  grid-template-rows: 0fr; 
  opacity: 0; 
  margin-top: 0; 
  margin-bottom: 0;
  width: 100%; 
  position: relative; 
  pointer-events: none;
  transition: grid-template-rows 0.3s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.25s ease, margin 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

#custom-comment-form-container.is-expanded { 
  grid-template-rows: 1fr; 
  opacity: 1; 
  pointer-events: auto; 
}

.comments-wrapper > #custom-comment-form-container.is-expanded { 
  margin-top: -5px; 
  margin-bottom: 15px; 
}

.item-control + #custom-comment-form-container.is-expanded { 
  margin-top: 15px; 
  margin-bottom: 15px; 
}

.form-inner { 
  min-height: 0; 
  display: flex; 
  flex-direction: column; 
  transform: translateZ(0); 
  overflow-x: auto; 
  overflow-y: hidden; 
  direction: rtl; 
  scrollbar-width: none; 
}

.form-inner::-webkit-scrollbar { 
  display: none; 
}

.comments-wrapper iframe#comment-editor {
  margin-left: 0 !important; 
  border: none; 
  background: transparent !important;
  height: 100px !important; 
  transition: filter 0.3s ease; 
  color-scheme: light !important;
  direction: ltr; 
  width: calc(100% + 54px) !important; 
  max-width: none !important;
  flex-shrink: 0;
}

[data-theme="dark"] .comments-wrapper iframe#comment-editor { 
  filter: invert(91%) hue-rotate(180deg) brightness(96%) !important; 
}

h4#comment-post-message, 
.comment-thread-toggle, 
.thread-toggle, 
.continue, 
.loadmore, 
.paging-control-container, 
.titlewrapper, 
.quickedit, 
.post-feeds, 
#Attribution1, 
.thread-count, 
.icon.action {
  display: none !important; 
  visibility: hidden !important; 
  opacity: 0 !important; 
  height: 0 !important; 
  width: 0 !important;
}

.comments .comment { 
  position: relative; 
  padding-left: 56px; 
  margin-bottom: 24px; 
  list-style: none !important; 
  overflow: visible !important; 
  padding-bottom: 0 !important; 
}

.comments .comment-block { 
  margin-left: 0 !important; 
  padding: 0 !important; 
} 

.thread-trunk {
  position: absolute !important; 
  left: 19px !important; 
  top: 45px !important; 
  bottom: 52px !important; 
  width: 2px !important; 
  background-color: var(--border-color) !important; 
  z-index: 1 !important; 
}

.comment-header { 
  display: flex; 
  align-items: center; 
  flex-wrap: wrap; 
  gap: 8px; 
  margin-bottom: 4px; 
}

.comment-author, 
.datetime { 
  display: inline-flex; 
  align-items: center; 
}

.comment-author a, 
.datetime a { 
  padding: 0; 
  min-height: auto; 
  border: none; 
  transition: color 0.3s ease; 
}

.comment-author { 
  font-weight: 600; 
  font-size: 0.95rem; 
}

.datetime { 
  font-size: 0.85rem; 
  color: var(--meta-color); 
}

.comment-content { 
  font-size: 0.95rem; 
  line-height: 1.6; 
  margin-bottom: 4px; 
  word-break: break-word; 
  border: none !important; 
  padding: 0 !important; 
  background: transparent !important; 
}

.avatar-image-container { 
  position: absolute !important; 
  left: 0; 
  top: 0 !important; 
  width: 40px !important; 
  height: 40px !important; 
  margin: 0 !important; 
}

.avatar-image-container img { 
  width: 100%; 
  height: 100%; 
  border-radius: 50%; 
  object-fit: cover; 
}

.comments .item-control { 
  display: flex !important; 
  flex-wrap: wrap; 
  gap: 16px; 
  margin-top: 6px; 
  align-items: center; 
}

.item-control .comment-reply { 
  display: inline-flex !important; 
}

.comments .item-control a { 
  min-height: auto; 
  padding: 6px 12px; 
  font-size: 0.85rem; 
  font-weight: 600; 
  border-radius: 16px; 
  background: transparent !important; 
  border: none !important;
  color: var(--text-color); 
  transition: background 0.2s ease; 
  cursor: pointer; 
}

.comments .item-control a:hover { 
  background: var(--btn-bg) !important; 
  transform: none; 
}

.comment-replies ol, 
.comment-replies ul, 
.comment-thread ol, 
.comment-thread ul {
  margin-left: 0 !important; 
  padding-left: 0 !important; 
  margin: 0 !important; 
  padding: 0 !important; 
  list-style: none !important; 
  border: none !important;
}

.comment-replies { 
  position: relative !important; 
  margin: 12px 0 0 -20px !important; 
  padding: 0 !important; 
}

.comment-replies .comment { 
  padding: 0 0 0 36px !important; 
  margin: 0 0 16px 0 !important; 
  position: relative !important; 
  overflow: visible !important; 
}

.comment-replies .avatar-image-container { 
  width: 24px !important; 
  height: 24px !important; 
  left: 0 !important; 
  top: 0 !important; 
  margin: 0 !important; 
  padding: 0 !important; 
  z-index: 2 !important; 
  position: absolute !important; 
}

.yt-branch {
  display: block !important; 
  position: absolute !important; 
  box-sizing: border-box !important; 
  left: -17px !important; 
  top: -20px !important; 
  width: 17px !important; 
  height: 32px !important; 
  border-left: 2px solid var(--border-color) !important; 
  border-bottom: 2px solid var(--border-color) !important; 
  border-bottom-left-radius: 16px !important; 
  border-top: none !important; 
  border-right: none !important; 
  background-color: transparent !important; 
  z-index: 1 !important; 
  pointer-events: none !important;
}

.replies-grid-wrapper { 
  display: grid; 
  grid-template-rows: 0fr; 
  opacity: 0; 
  pointer-events: none; 
  transition: grid-template-rows 0.4s cubic-bezier(0.25, 1, 0.5, 1), opacity 0.35s ease; 
}

.replies-grid-wrapper.is-expanded { 
  grid-template-rows: 1fr; 
  opacity: 1; 
  pointer-events: auto; 
}

.replies-grid-inner { 
  min-height: 0; 
  overflow: hidden; 
  padding-top: 4px; 
  margin-left: -30px !important; 
  padding-left: 30px !important; 
}

.reply-toggle-btn {
  position: relative; 
  background: transparent !important; 
  color: var(--accent-color) !important; 
  font-weight: 600; 
  font-size: 0.9rem; 
  padding: 6px 16px; 
  margin: 0 0 12px 0 !important; 
  border-radius: 18px; 
  display: inline-flex; 
  align-items: center; 
  gap: 6px; 
  min-height: 32px; 
  transition: background 0.2s ease; 
  cursor: pointer; 
  border: none; 
  font-family: inherit; 
  z-index: 2;
}

.reply-toggle-btn:hover { 
  background: var(--accent-bg) !important; 
  transform: none !important; 
}

.reply-toggle-btn svg { 
  width: 20px; 
  height: 20px; 
  transition: transform 0.3s ease; 
  fill: currentColor; 
}

.reply-toggle-btn.expanded svg { 
  transform: rotate(180deg); 
}

.reply-toggle-btn::before {
  content: '' !important; 
  display: block !important; 
  position: absolute !important; 
  box-sizing: border-box !important; 
  left: -17px !important; 
  top: -16px !important; 
  width: 17px !important; 
  height: 32px !important; 
  border-left: 2px solid var(--border-color) !important; 
  border-bottom: 2px solid var(--border-color) !important; 
  border-bottom-left-radius: 16px !important; 
  border-top: none !important; 
  border-right: none !important; 
  pointer-events: none !important; 
  z-index: 1 !important;
}

/* Footer */
.site-footer { 
  padding: 30px 0; 
  border-top: 1px solid var(--border-color); 
  text-align: center; 
  display: flex; 
  flex-direction: column; 
  align-items: center; 
  gap: 20px; 
  margin-top: 30px; 
}

.social-links { 
  display: flex; 
  gap: 16px; 
  justify-content: center; 
}

.social-links a { 
  display: inline-flex; 
  align-items: center; 
  justify-content: center; 
  width: 52px; 
  height: 52px; 
  background: rgba(0,0,0,0.03); 
  border-radius: 50%; 
  border: none; 
  transition: all 0.3s ease; 
}

[data-theme="dark"] .social-links a { 
  background: rgba(255,255,255,0.05); 
}

.social-links a:hover { 
  background: var(--border-color); 
  color: var(--accent-color); 
  transform: translateY(-3px); 
}

.social-links svg { 
  width: 24px; 
  height: 24px; 
  fill: currentColor; 
}

.copyright-text { 
  font-size: 0.85rem; 
  color: var(--meta-color); 
  padding: 12px 0; 
  min-height: 48px; 
}

/* Mobile layout */
@media (max-width: 600px) {
  .outer-wrapper { padding: 0 20px; }
  .site-header { padding: 60px 0 20px; text-align: left; }
  .header-logo-link svg { width: 65px !important; height: 65px !important; }
  .header-logo-link { flex-direction: row !important; align-items: center !important; gap: 12px !important; }
  .header-title h1 { font-size: 1.8rem; }

  nav.main-nav {
    overflow-x: auto; 
    -webkit-overflow-scrolling: touch; 
    scrollbar-width: none; 
    margin-left: -20px; 
    margin-right: -20px; 
    padding: 5px 20px; 
    margin-top: -5px; 
  }

  nav.main-nav::-webkit-scrollbar { display: none; }
  nav.main-nav ul { flex-direction: row; align-items: center; justify-content: flex-start; flex-wrap: nowrap; gap: 10px; }
  .main-nav li { margin: 0; flex-shrink: 0; }
  .main-nav li a { padding: 6px 16px; min-height: 38px; font-size: 0.85rem; }

  .comments .comment { padding-left: 46px !important; }
  .avatar-image-container { width: 34px !important; height: 34px !important; }
  .thread-trunk { left: 16px !important; top: 38px !important; bottom: 48px !important; }

  .comment-replies { margin-left: -16px !important; }
  .comment-replies .comment { padding-left: 28px !important; }
  .comment-replies .avatar-image-container { width: 20px !important; height: 20px !important; }
  .replies-grid-inner { margin-left: -20px !important; padding-left: 20px !important; }

  .yt-branch { left: -14px !important; width: 14px !important; height: 26px !important; top: -16px !important; border-bottom-left-radius: 12px !important; }
  .reply-toggle-btn::before { left: -14px !important; width: 14px !important; height: 26px !important; top: -10px !important; border-bottom-left-radius: 12px !important; }
}

b:if.script:
//
window.addEventListener('DOMContentLoaded', () => {
  const list = document.getElementById('related-posts-list');
  const wrapper = document.querySelector('.related-posts');
  if (!list) return;

  const label = list.getAttribute('data-label');
  if (!label) {
    if (wrapper) wrapper.style.display = 'none';
    return;
  }

  const currentUrl = window.location.href.split(/[?#]/)[0];

  window.loadRelatedPosts = json => {
    let html = '';
    if (json && json.feed && json.feed.entry) {
      const posts = json.feed.entry;
      let count = 0;
      for (let i = 0; i < posts.length; i++) {
        const title = posts[i].title.$t;
        let url = '';
        for (let j = 0; j < posts[i].link.length; j++) {
          if (posts[i].link[j].rel === 'alternate') {
            url = posts[i].link[j].href;
            break;
          }
        }
        if (url.split(/[?#]/)[0] === currentUrl) continue;

        html += '<li><a href="' + url + '">' + title + '</a></li>';
        count++;
        if (count >= 3) break; 
      }
    }
    if (html) {
      list.innerHTML = html;
    } else {
      if (wrapper) wrapper.style.display = 'none';
    }
  };

  const script = document.createElement('script');
  script.src = '/feeds/posts/default/-/' + encodeURIComponent(label) + '?alt=json-in-script&callback=loadRelatedPosts&max-results=6';
  document.body.appendChild(script);
});
