body.script:
//
const TEXT_REPLY = '<span class="lang-zh"><span class="variant-simp">回复</span><span class="variant-trad">回覆</span></span><span class="lang-en">Reply</span>';
const TEXT_CANCEL = '<span class="lang-zh"><span class="variant-simp">取消回复</span><span class="variant-trad">取消回覆</span></span><span class="lang-en">Cancel</span>';
const TEXT_WRITE = '<span class="lang-zh"><span class="variant-simp">写留言</span><span class="variant-trad">寫留言</span></span><span class="lang-en">Write a comment</span>';
const TEXT_COLLAPSE = '<span class="lang-zh"><span class="variant-simp">收起留言框</span><span class="variant-trad">收起留言框</span></span><span class="lang-en">Collapse comment box</span>';
const TEXT_DELETE = '<span class="lang-zh"><span class="variant-simp">删除</span><span class="variant-trad">刪除</span></span><span class="lang-en">Delete</span>';

window.addEventListener("load", () => {
  const root = document.documentElement;

  // Update copyright year
  const yearEl = document.getElementById("current-year");
  if (yearEl) yearEl.textContent = new Date().getFullYear();

  // UI transition effect
  const triggerContentFade = callback => {
      const targets = document.querySelectorAll('.site-header, nav.main-nav, #main-content, .site-footer, .top-actions');
      targets.forEach(el => el.classList.add('content-fade-out'));
      setTimeout(() => {
          callback();
          setTimeout(() => targets.forEach(el => el.classList.remove('content-fade-out')), 50); 
      }, 350); 
  };

  // Theme toggle logic
  const themeToggle = document.getElementById("theme-toggle");
  if (themeToggle) {
    themeToggle.addEventListener("click", () => {
      const newTheme = root.getAttribute("data-theme") === "dark" ? "light" : "dark";
      root.setAttribute("data-theme", newTheme);
      localStorage.setItem("theme", newTheme);
    });
  }

  // Language toggle logic
  const langToggle = document.getElementById("lang-toggle");
  if (langToggle) {
    langToggle.addEventListener("click", () => {
      triggerContentFade(() => {
          const newLang = root.getAttribute("data-lang") === "zh" ? "en" : "zh";
          root.setAttribute("data-lang", newLang);
          localStorage.setItem("lang", newLang);
      });
    });
  }

  // Text nodes walk helper
  const ignoreTags = new Set(["SCRIPT", "STYLE", "NOSCRIPT", "IFRAME", "CODE"]);
  const walkTextNodes = (node, applyConversion) => {
    const walker = document.createTreeWalker(node, NodeFilter.SHOW_TEXT, {
      acceptNode: n => ignoreTags.has(n.parentNode.nodeName) ? NodeFilter.FILTER_REJECT : NodeFilter.FILTER_ACCEPT
    }, false);

    let currentNode;
    while (currentNode = walker.nextNode()) {
        if (currentNode.nodeValue.trim()) currentNode.nodeValue = applyConversion(currentNode.nodeValue);
    }
  };

  // Simplified/Traditional conversion
  const loadOpenCC = (targetVariant, callback) => {
    const executeConversion = () => {
        const converter = window.OpenCC.Converter({
            from: targetVariant === "simp" ? "tw" : "cn",
            to: targetVariant === "simp" ? "cn" : "tw"
        });
        walkTextNodes(document.body, converter);
        root.setAttribute("data-variant", targetVariant);
        localStorage.setItem("variant", targetVariant);
        if (callback) callback();
    };

    if (window.OpenCC) {
      executeConversion();
    } else {
      const script = document.createElement("script");
      script.src = "https://cdn.jsdelivr.net/npm/opencc-js@1.0.5/dist/umd/full.js";
      script.async = true;
      script.defer = true;
      script.onload = executeConversion;
      document.head.appendChild(script);
    }
  };

  // Initialize variant
  if (root.getAttribute("data-variant") === "trad") {
    setTimeout(() => loadOpenCC("trad"), 200);
  }

  const variantToggle = document.getElementById("variant-toggle");
  if (variantToggle) {
    variantToggle.addEventListener("click", () => {
      triggerContentFade(() => loadOpenCC(root.getAttribute("data-variant") === "simp" ? "trad" : "simp"));
    });
  }
});
