//
window.addEventListener("DOMContentLoaded", () => {

  // Lazy load images
  document.querySelectorAll(".post-body img").forEach(img => {
    if (!img.hasAttribute("loading")) img.setAttribute("loading", "lazy");
  });

  // Adjust typography based on language
  document.querySelectorAll('.post-outer').forEach(post => {
      const body = post.querySelector('.post-body');
      if (!body) return;

      const tagNodes = post.querySelectorAll('.post-tag, .hidden-tag');
      const tags = Array.from(tagNodes).map(t => {
          const raw = t.getAttribute('data-raw-tag') || t.textContent;
          return raw.trim().toLowerCase();
      });

      if (tags.includes('english') || tags.includes('en')) {
          body.style.lineHeight = '1.7'; 
          body.style.textAlign = 'left';
          body.setAttribute('lang', 'en'); 
          body.style.webkitHyphens = 'auto';
          body.style.hyphens = 'auto';
          body.style.wordSpacing = '0.05em';
      } else {
          body.style.lineHeight = '2.2';
          body.style.textAlign = 'justify';
          body.setAttribute('lang', 'zh-Hans');
          body.style.webkitHyphens = 'none';
          body.style.hyphens = 'none';
          body.style.wordSpacing = 'normal';
      }
  });

  // Static translation map to reduce API calls
  const navDictionary = {
      "Home": { zh: "首页", en: "Home" },
      "首页": { zh: "首页", en: "Home" },
      "中文": { zh: "中文", en: "Chinese" },
      "English": { zh: "英文", en: "English" },
      "Life": { zh: "生活", en: "Life" },
      "生活": { zh: "生活", en: "Life" },
      "Tech": { zh: "科技", en: "Tech" },
      "科技": { zh: "科技", en: "Tech" },
      "Art": { zh: "艺术", en: "Art" },
      "艺术": { zh: "艺术", en: "Art" }
  };

  // Fetch translations
  async function fetchTranslation(text, targetLang) {
      const cacheKey = `tag_trans_v7_${text}_${targetLang}`;
      const cached = localStorage.getItem(cacheKey);
      if (cached) return cached;

      try {
          const url = `https://translate.googleapis.com/translate_a/single?client=gtx&sl=auto&tl=${targetLang}&dt=t&q=${encodeURIComponent(text)}`;
          const response = await fetch(url);
          const data = await response.json();
          let translatedText = data[0][0][0];

          localStorage.setItem(cacheKey, translatedText);
          return translatedText;
      } catch (error) {
          console.error("Translation Endpoint Denied:", text, error);
          return text; 
      }
  }

  // Get missing translations dynamically
  async function getTranslations(rawTag) {
      if (navDictionary[rawTag]) return navDictionary[rawTag];

      const isChinese = /[\u4e00-\u9fa5]/.test(rawTag);
      let zhText = rawTag;
      let enText = rawTag;

      if (isChinese) {
          enText = await fetchTranslation(rawTag, 'en');
          enText = enText.charAt(0).toUpperCase() + enText.slice(1);
      } else {
          zhText = await fetchTranslation(rawTag, 'zh-CN');
      }

      return { zh: zhText, en: enText };
  }

  // Apply translations to tags
  document.querySelectorAll('.translatable-tag').forEach(async (link) => {
      const rawTag = link.getAttribute('data-raw-tag');
      const enSpan = link.querySelector('.lang-en');
      const zhSpan = link.querySelector('.lang-zh');

      if (rawTag) {
          const trans = await getTranslations(rawTag);
          if (zhSpan) zhSpan.textContent = trans.zh;
          if (enSpan) enSpan.textContent = trans.en;
      }
  });
});
