b:if.script:
//
// Initialize comment form UI
window.addEventListener("load", () => {
  const commentToggleBtn = document.getElementById("comment-toggle");
  const commentsWrapper = document.querySelector(".comments-wrapper");
  const customFormContainer = document.getElementById("custom-comment-form-container");
  let attempts = 0;

  const initializeCommentIframe = () => {
    const editorIframe = document.getElementById("comment-editor");
    if (editorIframe && customFormContainer && commentsWrapper) {
      const formInner = document.createElement('div');
      formInner.className = 'form-inner';
      formInner.appendChild(editorIframe);
      customFormContainer.appendChild(formInner);

      commentsWrapper.classList.add("show-main-form");
      customFormContainer.classList.add("is-expanded");
      if (commentToggleBtn) commentToggleBtn.innerHTML = TEXT_COLLAPSE;
    } else if (attempts < 25) {
      attempts++;
      setTimeout(initializeCommentIframe, 200);
    }
  };
  initializeCommentIframe();

  if (commentToggleBtn && commentsWrapper && customFormContainer) {
    commentToggleBtn.addEventListener("click", e => {
      e.preventDefault();
      const editorIframe = document.getElementById("comment-editor");
      const isExpanded = commentsWrapper.classList.contains("show-main-form");

      document.querySelectorAll(".comment-reply.cancel-active").forEach(btn => {
          btn.classList.remove("cancel-active");
          btn.innerHTML = TEXT_REPLY;
      });

      if (isExpanded) {
        commentsWrapper.classList.remove("show-main-form");
        commentToggleBtn.innerHTML = TEXT_WRITE;
        customFormContainer.classList.remove("is-expanded");
      } else {
        const mainComments = document.getElementById("comments");
        if (mainComments && customFormContainer) {
            commentsWrapper.insertBefore(customFormContainer, mainComments);
        }
        const formInner = customFormContainer.querySelector('.form-inner');
        if (editorIframe && formInner && !formInner.contains(editorIframe)) {
            formInner.appendChild(editorIframe);
        }
        const srcLink = document.getElementById("comment-editor-src");
        if (srcLink && editorIframe && editorIframe.src !== srcLink.href) {
            editorIframe.src = srcLink.href;
        }
        commentsWrapper.classList.add("show-main-form");
        commentToggleBtn.innerHTML = TEXT_COLLAPSE;
        void customFormContainer.offsetWidth; 
        customFormContainer.classList.add("is-expanded");
      }
    });
  }

  document.body.addEventListener("click", e => {
      const replyBtn = e.target.closest(".comment-reply");
      if (replyBtn) {
          const isCancel = replyBtn.classList.contains("cancel-active");
          const iframe = document.getElementById("comment-editor");
          const formInner = customFormContainer.querySelector('.form-inner');

          if (iframe) { iframe.style.transition = 'none'; iframe.style.opacity = '0'; }
          if (customFormContainer) { customFormContainer.style.transition = 'none'; customFormContainer.classList.remove("is-expanded"); }

          setTimeout(() => {
              document.querySelectorAll(".comment-reply.cancel-active").forEach(btn => {
                  if (btn !== replyBtn) {
                      btn.classList.remove("cancel-active");
                      btn.innerHTML = TEXT_REPLY;
                  }
              });

              if (isCancel) {
                  replyBtn.classList.remove("cancel-active");
                  replyBtn.innerHTML = TEXT_REPLY;
                  const mainComments = document.getElementById("comments");
                  if (mainComments && customFormContainer && formInner && iframe) {
                      formInner.appendChild(iframe);
                      commentsWrapper.insertBefore(customFormContainer, mainComments);
                      const srcLink = document.getElementById("comment-editor-src");
                      if (srcLink) iframe.src = srcLink.href; 
                  }
                  if (commentsWrapper) commentsWrapper.classList.add("show-main-form");
                  if (commentToggleBtn) commentToggleBtn.innerHTML = TEXT_COLLAPSE;
              } else {
                  replyBtn.classList.add("cancel-active");
                  replyBtn.innerHTML = TEXT_CANCEL;
                  if (commentsWrapper) commentsWrapper.classList.remove("show-main-form");
                  if (commentToggleBtn) commentToggleBtn.innerHTML = TEXT_WRITE;
                  const itemControl = replyBtn.closest(".item-control");
                  if (itemControl && customFormContainer && formInner && iframe) {
                      itemControl.insertAdjacentElement('afterend', customFormContainer);
                      formInner.appendChild(iframe);
                  }
              }

              if (customFormContainer) {
                  void customFormContainer.offsetWidth; 
                  customFormContainer.style.transition = ''; 
                  customFormContainer.classList.add("is-expanded");
              }
              if (iframe) {
                  setTimeout(() => {
                      iframe.style.transition = 'opacity 0.4s ease';
                      iframe.style.opacity = '1';
                  }, 50);
              }
          }, 20);
      }
  }, true);
});

// Monitor DOM to restructure comments
let commentTimer;
const commentObserver = new MutationObserver(() => {
  clearTimeout(commentTimer);
  commentTimer = setTimeout(() => {

    // Localize native delete buttons
    document.querySelectorAll(".item-control a:not([data-cleaned-del])").forEach(btn => {
      const lowerText = btn.innerText.trim().toLowerCase();
      if (lowerText === "delete" || lowerText === "删除") {
          btn.innerHTML = TEXT_DELETE;
          btn.dataset.cleanedDel = "true";
      }
    });

    // Clean up comment controls
    document.querySelectorAll(".comment:not([data-cleaned])").forEach(comment => {
      const controls = comment.querySelector(".item-control");
      const replyBtns = comment.querySelectorAll(".comment-reply");
      if (controls && replyBtns.length) {
        controls.appendChild(replyBtns[0]);
        replyBtns[0].style.display = "inline-flex";
        replyBtns[0].innerHTML = replyBtns[0].classList.contains("cancel-active") ? TEXT_CANCEL : TEXT_REPLY;
        for (let i = 1; i < replyBtns.length; i++) replyBtns[i].remove();
        comment.dataset.cleaned = "true";
      }
    });

    // Add branch visuals and toggle capabilities
    document.querySelectorAll(".comment-replies:not([data-folded])").forEach(thread => {
      const ol = thread.querySelector("ol");
      const nestedComments = thread.querySelectorAll(".comment");

      if (ol && nestedComments.length > 0) {
        const parentComment = thread.closest('.comment');

        if (parentComment && !parentComment.querySelector(':scope > .thread-trunk')) {
            const trunk = document.createElement('div');
            trunk.className = 'thread-trunk';
            parentComment.insertBefore(trunk, parentComment.firstChild);
        }

        const wrapper = document.createElement("div");
        wrapper.className = "replies-grid-wrapper";
        const inner = document.createElement("div");
        inner.className = "replies-grid-inner";

        ol.parentNode.insertBefore(wrapper, ol);
        wrapper.appendChild(inner);
        inner.appendChild(ol);

        const toggleBtn = document.createElement("button");
        const hiddenCount = nestedComments.length;
        toggleBtn.className = "reply-toggle-btn";
        toggleBtn.dataset.count = hiddenCount;

        const getBtnHtml = isExpanded => {
          const arrowSvg = `<svg viewBox="0 0 24 24"><path d="M7 10l5 5 5-5z"/></svg>`;
          if (isExpanded) {
              return `${arrowSvg}<span class="lang-zh"><span class="variant-simp">收起回复</span><span class="variant-trad">收起回覆</span></span><span class="lang-en">Collapse replies</span>`;
          } else {
              const enText = hiddenCount === 1 ? 'reply' : 'replies';
              return `${arrowSvg}<span class="lang-zh"><span class="variant-simp">${hiddenCount} 条回复</span><span class="variant-trad">${hiddenCount} 則回覆</span></span><span class="lang-en">${hiddenCount} ${enText}</span>`;
          }
        };

        toggleBtn.innerHTML = getBtnHtml(false);

        toggleBtn.onclick = e => {
          e.preventDefault();
          const isExpanded = toggleBtn.classList.contains("expanded");
          if (isExpanded) {
             wrapper.classList.remove("is-expanded");
          } else {
             wrapper.classList.add("is-expanded");
          }
          toggleBtn.classList.toggle("expanded");
          toggleBtn.innerHTML = getBtnHtml(!isExpanded);
        };

        if (wrapper.nextSibling) {
            wrapper.parentNode.insertBefore(toggleBtn, wrapper.nextSibling);
        } else {
            wrapper.parentNode.appendChild(toggleBtn);
        }

        thread.dataset.folded = "true";
      }
    });

    document.querySelectorAll(".comment-replies .comment:not([data-branched])").forEach(childComment => {
        const branch = document.createElement('div');
        branch.className = 'yt-branch';
        childComment.insertBefore(branch, childComment.firstChild);
        childComment.dataset.branched = "true";
    });

    const commentContainer = document.querySelector(".comments-wrapper");
    if (commentContainer) {
      commentContainer.querySelectorAll("a, span").forEach(el => {
        const lowerText = el.innerText.trim().toLowerCase();
        if (lowerText === "load more..." || lowerText.includes("load more")) el.remove();
      });
    }

  }, 150);
});

window.addEventListener("DOMContentLoaded", () => {
  const commentContainer = document.getElementById("comments") || document.querySelector(".comments-wrapper");
  if (commentContainer) {
    commentObserver.observe(commentContainer, { childList: true, subtree: true });
  }
});
